Sure! With sqlx you write SQL as a macro and it checks types at compile time, e.g.:
```rust
#[sqlx::table(name = "users")]
struct User { id: i32, name: String };

#[sqlx::query(sql = "SELECT * FROM users WHERE name = $name")]
fn get_user_by_name(db: &SqliteDatabase, name: &str) -> Result<Option<User>, sqlx::Error> {
    db.prepare("SELECT * FROM users WHERE name = \?").execute(&[name])
}
