```rust
use diesel::prelude::*;

async fn get_user(pool: &PgPool, username: &str) -> Result<User, sqlx::Error> {
    let user = sqlx::query_as!(User, "SELECT id, username, email FROM users WHERE username = ", username)
        .fetch_one(pool).await?;
    Ok(user)
}
```
And for SQLx with async:

```rust
async fn get_user_sqlx(pool: &PgPool, username: &str) -> Result<User, sqlx::Error> {
    let user = sqlx::query_as!(User, "SELECT id, username, email FROM users WHERE username = $1", username)
        .fetch_one(pool).await?;
    Ok(user)
}
```
Note how in SQLx, the `$1` syntax is used for parameters; this helps avoid silent mistakes.
